import React, { useEffect, useState } from "react";
import axios from "axios";

export default function AdminDashboard() {
  const [foods, setFoods] = useState([]);
  const [file, setFile] = useState(null);
  const [form, setForm] = useState({ name: "", description: "", price: "", category: "" });

  useEffect(() => {
    fetchFoods();
  }, []);

  const fetchFoods = async () => {
    const res = await axios.get("/api/foods");
    setFoods(res.data);
  };

  const handleAddFood = async () => {
    const formData = new FormData();
    formData.append("name", form.name);
    formData.append("description", form.description);
    formData.append("price", form.price);
    formData.append("category", form.category);
    if (file) formData.append("image", file);

    await axios.post("/api/foods/add-item", formData, { headers: { "Content-Type": "multipart/form-data" } });
    setForm({ name: "", description: "", price: "", category: "" });
    setFile(null);
    fetchFoods();
  };

  const handleDelete = async (id) => {
    await axios.delete(`/api/foods/manage/${id}`);
    fetchFoods();
  };

  const handleTodayMenu = async (id) => {
    await axios.post("/api/foods/set-today-menu", { foodId: id });
    alert("Marked as today’s menu");
  };

  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold mb-4">Admin Dashboard</h1>

      {/* Add Food Form */}
      <div className="mb-6 bg-white p-4 rounded shadow">
        <h2 className="text-lg font-semibold mb-2">Add Food</h2>
        <input placeholder="Name" value={form.name} onChange={e => setForm({...form, name:e.target.value})} className="border p-1 m-1" />
        <input placeholder="Description" value={form.description} onChange={e => setForm({...form, description:e.target.value})} className="border p-1 m-1" />
        <input placeholder="Price" type="number" value={form.price} onChange={e => setForm({...form, price:e.target.value})} className="border p-1 m-1" />
        <input placeholder="Category" value={form.category} onChange={e => setForm({...form, category:e.target.value})} className="border p-1 m-1" />
        <input type="file" onChange={e => setFile(e.target.files[0])} className="m-1" />
        <button onClick={handleAddFood} className="bg-emerald-500 text-white px-3 py-1 rounded m-1">Add Food</button>
      </div>

      {/* Foods List */}
      <div className="bg-white p-4 rounded shadow">
        <h2 className="text-lg font-semibold mb-2">Foods</h2>
        {foods.map(food => (
          <div key={food._id} className="flex items-center justify-between border p-2 rounded mb-2">
            <div className="flex items-center gap-2">
              {food.img && <img src={`/uploads/${food.img}`} alt={food.name} className="w-12 h-12 object-cover rounded" />}
              <div>
                <div>{food.name}</div>
                <div className="text-sm text-gray-500">₹{food.price}</div>
                <div className="text-sm text-gray-500">{food.available ? "Available" : "Unavailable"}</div>
              </div>
            </div>
            <div className="flex gap-2">
              <button onClick={() => handleTodayMenu(food._id)} className="px-2 py-1 border rounded text-sm">Today Menu</button>
              <button onClick={() => handleDelete(food._id)} className="px-2 py-1 border rounded text-sm text-red-600">Delete</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
